import{_ as e}from"./chunks/sign-up.B6w_QBvP.js";import{_ as d}from"./chunks/wallet.7Yk7pML4.js";import{_ as a}from"./chunks/create-key.HFKpZi27.js";import{_ as r}from"./chunks/pricing.xnwHCEuz.js";import{_ as o,o as i,c as n,a2 as c}from"./chunks/framework.BflysNKA.js";const q=JSON.parse('{"title":"macOS 快速接入","description":"","frontmatter":{},"headers":[],"relativePath":"beginner/macos.md","filePath":"beginner/macos.md","lastUpdated":1780486302000}'),s={name:"beginner/macos.md"};function l(h,t,p,m,b,u){return i(),n("div",null,[...t[0]||(t[0]=[c('<h1 id="macos-快速接入" tabindex="-1">macOS 快速接入 <a class="header-anchor" href="#macos-快速接入" aria-label="Permalink to &quot;macOS 快速接入&quot;">​</a></h1><p>适用于 Apple 芯片（M1/M2/M3/M4）和 Intel Mac。从零开始到第一次成功调用 AI，按顺序完成以下步骤。</p><h2 id="先确认你的-mac-芯片" tabindex="-1">先确认你的 Mac 芯片 <a class="header-anchor" href="#先确认你的-mac-芯片" aria-label="Permalink to &quot;先确认你的 Mac 芯片&quot;">​</a></h2><p>点击左上角 → <strong>关于本机</strong>：</p><table tabindex="0"><thead><tr><th>看到什么</th><th>芯片类型</th><th>安装包选</th></tr></thead><tbody><tr><td>Apple M1 / M2 / M3 / M4</td><td>Apple 芯片</td><td><code>arm64</code></td></tr><tr><td>Intel Core i5 / i7 / i9</td><td>Intel</td><td><code>x64</code></td></tr></tbody></table><p>后面安装 Node.js 等软件时，需要选对应架构的安装包。</p><h2 id="整体流程" tabindex="-1">整体流程 <a class="header-anchor" href="#整体流程" aria-label="Permalink to &quot;整体流程&quot;">​</a></h2><p>和 Windows 一样，分为两个阶段：</p><p><strong>第一阶段：在 小蓝中转站控制台准备好三样东西</strong>（不需要装任何软件）</p><ol><li>注册账号</li><li>充值余额（¥10 即可）</li><li>创建 API 密钥</li></ol><p><strong>第二阶段：选一个工具，把三样东西填进去</strong></p><table tabindex="0"><thead><tr><th>我想做什么</th><th>用什么工具</th><th>难度</th><th>需要先装什么</th></tr></thead><tbody><tr><td>先确认接口能不能用</td><td><a href="/beginner/macos-cherry-studio">Cherry Studio</a></td><td>最简单</td><td>什么都不用装，下载客户端即可</td></tr><tr><td>在项目里直接改代码</td><td><a href="/beginner/macos-claude-code">Claude Code</a></td><td>中等</td><td>命令行工具 + Git</td></tr><tr><td>习惯 OpenAI 风格 CLI</td><td><a href="/beginner/macos-codex">Codex</a></td><td>中等</td><td>Git + Node.js</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">第一次用 小蓝中转站？</p><p>推荐先走 <strong>Cherry Studio</strong> 路径。不需要装命令行工具，下载一个桌面客户端就能测试。确认接口通了之后，再去配 Claude Code 或 Codex。</p></div><h2 id="第一阶段-在-xiaolan-准备三样东西" tabindex="-1">第一阶段：在 小蓝中转站 准备三样东西 <a class="header-anchor" href="#第一阶段-在-xiaolan-准备三样东西" aria-label="Permalink to &quot;第一阶段：在 小蓝中转站 准备三样东西&quot;">​</a></h2><h3 id="_1-注册账号" tabindex="-1">1. 注册账号 <a class="header-anchor" href="#_1-注册账号" aria-label="Permalink to &quot;1. 注册账号&quot;">​</a></h3><p>打开 <a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">小蓝中转站 官网</a>，点击右上角 <strong>注册</strong>。</p><p><img src="'+e+'" alt="注册页面 — 填写用户名、密码、确认密码，勾选人机验证后点击「创建账户」"></p><p>填写用户名和密码，勾选人机验证，点击 <strong>创建账户</strong>。注册成功后登录。</p><p>详细步骤见 <a href="/guide/registration">注册账号</a>。</p><h3 id="_2-充值-¥10" tabindex="-1">2. 充值 ¥10 <a class="header-anchor" href="#_2-充值-¥10" aria-label="Permalink to &quot;2. 充值 ¥10&quot;">​</a></h3><p>登录后点击左侧导航栏 <strong>钱包</strong>，选 ¥10，用支付宝或微信完成支付。</p><p><img src="'+d+'" alt="钱包页面 — 选择金额和付款方式"></p><p>第一次只需要 ¥10 跑通流程。详见 <a href="/guide/recharge">充值</a>。</p><h3 id="_3-创建-api-密钥" tabindex="-1">3. 创建 API 密钥 <a class="header-anchor" href="#_3-创建-api-密钥" aria-label="Permalink to &quot;3. 创建 API 密钥&quot;">​</a></h3><p>点击侧边栏 <strong>API 密钥</strong> → 左上角 <strong>创建 API 密钥</strong>：</p><p><img src="'+a+'" alt="创建 API 密钥 — 填写名称、选择分组、设置额度"></p><ul><li><strong>名称</strong>：填 <code>Mac-Claude</code> 或 <code>Mac-Codex</code></li><li><strong>分组</strong>：保持 <code>auto</code></li><li><strong>额度</strong>：先开 <strong>无限配额</strong></li></ul><p>点击 <strong>保存修改</strong> 后，新建的 Key 会<strong>出现在列表里（不会弹窗）</strong>。把鼠标移到 <strong>API 密钥</strong> 那一列，点出现的复制按钮，<strong>立即复制完整 Key</strong>（以 <code>sk-</code> 开头）。完整 Key 只能复制这一次，之后列表只显示前后几位，所以请马上保存好。</p><p>详见 <a href="/guide/create-key">创建专属 Key</a>。</p><h3 id="_4-复制模型名" tabindex="-1">4. 复制模型名 <a class="header-anchor" href="#_4-复制模型名" aria-label="Permalink to &quot;4. 复制模型名&quot;">​</a></h3><p>点击顶部导航 <strong>模型广场</strong>，点击模型名即可复制：</p><p><img src="'+r+'" alt="模型广场 — 点击模型名称可以直接复制"></p><p><strong>不要自己编模型名</strong>，以这里显示的为准。</p><h3 id="到这里你已经准备好了" tabindex="-1">到这里你已经准备好了： <a class="header-anchor" href="#到这里你已经准备好了" aria-label="Permalink to &quot;到这里你已经准备好了：&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>你应该有什么</th><th>示例</th></tr></thead><tbody><tr><td>账号</td><td>已注册并登录</td><td>✅</td></tr><tr><td>余额</td><td>≥ ¥10</td><td>✅</td></tr><tr><td>API Key</td><td>以 <code>sk-</code> 开头</td><td><code>sk-xxxxxxxxxxxxxx</code></td></tr><tr><td>模型名</td><td>从模型广场复制</td><td><code>claude-haiku-4-5-20251001</code></td></tr></tbody></table><h2 id="第二阶段-选一个工具开始" tabindex="-1">第二阶段：选一个工具开始 <a class="header-anchor" href="#第二阶段-选一个工具开始" aria-label="Permalink to &quot;第二阶段：选一个工具开始&quot;">​</a></h2><h3 id="路径-a-cherry-studio-最快验证" tabindex="-1">路径 A：Cherry Studio（最快验证） <a class="header-anchor" href="#路径-a-cherry-studio-最快验证" aria-label="Permalink to &quot;路径 A：Cherry Studio（最快验证）&quot;">​</a></h3><p>不需要装命令行工具。从 <a href="https://www.cherry-ai.com/" target="_blank" rel="noreferrer">Cherry Studio 官网</a> 下载安装后，按 <a href="/beginner/macos-cherry-studio">Cherry Studio 接入指南</a> 配置。</p><h3 id="路径-b-claude-code-终端改代码" tabindex="-1">路径 B：Claude Code（终端改代码） <a class="header-anchor" href="#路径-b-claude-code-终端改代码" aria-label="Permalink to &quot;路径 B：Claude Code（终端改代码）&quot;">​</a></h3><p>需要先安装环境。按顺序完成：</p><ol><li>→ <a href="/beginner/macos-env">macOS 环境准备</a>（命令行工具 + Homebrew + Git）</li><li>→ <a href="/beginner/macos-claude-code">macOS 接入 Claude Code</a></li></ol><h3 id="路径-c-codex-openai-风格-cli" tabindex="-1">路径 C：Codex（OpenAI 风格 CLI） <a class="header-anchor" href="#路径-c-codex-openai-风格-cli" aria-label="Permalink to &quot;路径 C：Codex（OpenAI 风格 CLI）&quot;">​</a></h3><p>需要先安装环境。按顺序完成：</p><ol><li>→ <a href="/beginner/macos-env">macOS 环境准备</a>（命令行工具 + Node.js）</li><li>→ <a href="/beginner/macos-codex">macOS 接入 Codex</a></li></ol><h2 id="故障速查" tabindex="-1">故障速查 <a class="header-anchor" href="#故障速查" aria-label="Permalink to &quot;故障速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>先查什么</th><th>怎么处理</th></tr></thead><tbody><tr><td><code>xcode-select</code> 弹窗提示安装</td><td>命令行工具未装</td><td>点击弹窗中的「安装」，等完成</td></tr><tr><td><code>command not found: brew</code></td><td>Homebrew 未装或 PATH 缺失</td><td>检查 PATH 是否包含 <code>/opt/homebrew/bin</code></td></tr><tr><td><code>node</code> / <code>npm</code> 命令不存在</td><td>Node.js 未装</td><td>重装 Node.js 后关闭终端重新打开</td></tr><tr><td>npm 权限错误</td><td>安装方式问题</td><td>用 Homebrew 装 Node.js（<code>brew install node</code>），避免 sudo</td></tr><tr><td><code>.zshrc</code> 改了但不生效</td><td>终端未重载</td><td><code>source ~/.zshrc</code> 或关闭终端重新打开</td></tr><tr><td>macOS 拦截应用打开</td><td>安全策略</td><td>系统设置 → 隐私与安全性 → 允许打开</td></tr><tr><td>提示 Key 无效</td><td>Key 状态</td><td>回控制台检查 Key 是否启用、余额是否充足</td></tr><tr><td>提示模型不存在</td><td>模型名</td><td>回模型广场重新复制完整模型名</td></tr><tr><td>连不上、一直转圈</td><td>Base URL</td><td>Claude Code/Gemini CLI 不加 <code>/v1</code>；Codex 必须加 <code>/v1</code></td></tr></tbody></table><p>遇到这些没解决的问题，带着完整报错截图去 <a href="/support/troubleshooting">排障手册</a>。</p>',47)])])}const y=o(s,[["render",l]]);export{q as __pageData,y as default};
